content.query:
let etipIndicators = ThreatIntelligenceIndicator
| where SourceSystem == "IntelWatch ETIP"
| where TimeGenerated {TimeRange};
let matched = etipIndicators
| join kind=inner (SecurityAlert | where TimeGenerated {TimeRange}) on $left.NetworkIP == $right.CompromisedEntity
| summarize MatchedIOCs = dcount(ExternalIndicatorId);
let total = etipIndicators | summarize TotalIOCs = dcount(ExternalIndicatorId);
matched | extend TotalIOCs = toscalar(total | project TotalIOCs)
| extend MatchRate = round(todouble(MatchedIOCs) / todouble(TotalIOCs) * 100, 2)
